// Get AI output text
const text = $json.output;

// Helper to extract values after labels
function extract(label) {
  const idx = text.indexOf(label);
  if (idx === -1) return "";
  return text
    .slice(idx + label.length)
    .trim()
    .split("\n")[0]
    .trim();
}

// n8n REQUIRES returning an ARRAY
  return [
  {
    subject: extract("SUBJECT:"),
    body: extract("BODY:"),
    productName: extract("PRODUCT_NAME:"),
    affiliateLink: extract("AFFILIATE_LINK:")
    // ❌ NO imageUrl here
  }
];

